/*
 * Karnaugh Map (K-Map) Minimization - C Implementation
 * Demonstrates K-Map creation, Gray code ordering, and simplification
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_VARS 4
#define MAX_CELLS 16

typedef struct {
 int num_vars;
 int size;
 int kmap[MAX_CELLS];
 int minterms[MAX_CELLS];
 int minterm_count;
} KMap;

// Initialize K-Map
void init_kmap(KMap *km, int num_vars) {
 km->num_vars = num_vars;
 km->size = 1 << num_vars; // 2^num_vars
 km->minterm_count = 0;

 // Initialize all cells to 0
 for (int i = 0; i < km->size; i++) {
 km->kmap[i] = 0;
 }
}

// Plot minterms on K-Map
void plot_minterms(KMap *km, int *minterms, int count) {
 km->minterm_count = count;
 for (int i = 0; i < count; i++) {
 if (minterms[i] >= 0 && minterms[i] < km->size) {
 km->kmap[minterms[i]] = 1;
 }
 }
}

// Generate Gray code
int gray_code(int n) {
 return n ^ (n >> 1);
}

// Convert minterm to binary string
void minterm_to_binary(int m, int num_vars, char *binary) {
 for (int i = num_vars - 1; i >= 0; i--) {
 binary[num_vars - 1 - i] = (m & (1 << i)) ? '1' : '0';
 }
 binary[num_vars] = '\0';
}

// Display K-Map (for 3 variables)
void display_kmap_3var(KMap *km) {
 printf("\n3-Variable K-Map:\n");
 printf(" BC\\A | 00 01 11 10\n");
 printf(" -----|-------------------\n");

 int gray_bc[4];
 for (int i = 0; i < 4; i++) {
 gray_bc[i] = gray_code(i);
 }

 for (int row = 0; row < 2; row++) {
 int bc_val = gray_bc[row * 2];
 printf("A=%d B=%d C=%d | ", 
 (gray_bc[row] >> 1) & 1,
 gray_bc[row] & 1,
 row);

 // Columns in Gray code order: 00, 01, 11, 10
 int cols[] = {0, 1, 3, 2};
 for (int c = 0; c < 4; c++) {
 int col = cols[c];
 int idx = row * 4 + col;
 printf(" %d ", km->kmap[idx]);
 }
 printf("\n");
 }
}

// Check if all cells in a group are 1s
int check_group(int *cells, int count, int *kmap) {
 for (int i = 0; i < count; i++) {
 if (kmap[cells[i]] != 1) {
 return 0;
 }
 }
 return 1;
}

// Find product term from group (simplified for example)
void find_product_term(KMap *km, int *cells, int count, char *result) {
 strcpy(result, "");

 if (km->num_vars == 3) {
 // For 3-variable K-Map example
 // Check each position in binary (A, B, C)
 char a_vals[4], b_vals[4], c_vals[4];

 for (int i = 0; i < count; i++) {
 char binary[4];
 minterm_to_binary(cells[i], 3, binary);
 a_vals[i] = binary[0];
 b_vals[i] = binary[1];
 c_vals[i] = binary[2];
 }

 // Check if variable changes in group (eliminate) or stays constant
 int a_all_0 = 1, a_all_1 = 1;
 int b_all_0 = 1, b_all_1 = 1;

 for (int i = 0; i < count; i++) {
 if (a_vals[i] == '1') a_all_0 = 0;
 if (a_vals[i] == '0') a_all_1 = 0;
 if (b_vals[i] == '1') b_all_0 = 0;
 if (b_vals[i] == '0') b_all_1 = 0;
 }

 // B is constant 0 in corners -> B'
 if (b_all_0) {
 strcpy(result, "B'");
 } else if (b_all_1) {
 strcpy(result, "B");
 }
 }
}

// Find and display groups (simplified demonstration)
void find_groups(KMap *km) {
 printf("\nGrouping Analysis:\n");

 if (km->num_vars == 3) {
 // For F(A,B,C) = Σm(0,2,3,4,6)
 // Check for group of 4 corners: m0, m2, m4, m6
 int corners[4] = {0, 2, 4, 6};
 if (check_group(corners, 4, km->kmap)) {
 printf(" Group 1: Cells [0, 2, 4, 6] (size 4)\n");
 printf(" -> Variable A: changes (eliminated)\n");
 printf(" -> Variable B: constant 0 -> B'\n");
 printf(" -> Variable C: changes (eliminated)\n");
 printf(" -> Product term: B'\n");
 }

 // Check for group of 2: m2, m3
 int top_row[2] = {2, 3};
 if (check_group(top_row, 2, km->kmap)) {
 printf(" Group 2: Cells [2, 3] (size 2)\n");
 printf(" -> Variable A: constant 0 -> A'\n");
 printf(" -> Variable B: constant 1 -> B\n");
 printf(" -> Variable C: changes (eliminated)\n");
 printf(" -> Product term: A'B\n");
 }
 }
}

// Main function - Example: F(A,B,C) = Σm(0,2,3,4,6)
int main() {
 printf("====================================\n");
 printf("Karnaugh Map Minimization Example\n");
 printf("====================================\n");
 printf("Function: F(A,B,C) = Σm(0, 2, 3, 4, 6)\n");

 // Create 3-variable K-Map
 KMap km;
 init_kmap(&km, 3);

 // Plot minterms
 int minterms[] = {0, 2, 3, 4, 6};
 plot_minterms(&km, minterms, 5);

 // Display K-Map
 display_kmap_3var(&km);

 // Find groups
 find_groups(&km);

 // Result
 printf("\n====================================\n");
 printf("Simplified Expression: F = B' + A'B\n");
 printf("====================================\n");

 return 0;
}
